consumer_query_patterns:
// All illegal cross-layer imports in the shared KMP module
MATCH (v:ImportViolation {source_module: 'shared'})
RETURN v.file_path, v.violation_rule, v.target_module ORDER BY v.file_path

// Direct dependency graph of a module — one hop
MATCH (m:Module {name: $module_name})-[:DEPENDS_ON]->(dep:Module)
RETURN dep.name, dep.kind, dep.build_system

// Find all modules that illegally access the data layer from presentation
MATCH (src:Module {kind: 'presentation'})-[e:DEPENDS_ON {is_illegal: true}]->(tgt:Module {kind: 'data'})
RETURN src.name, tgt.name

// Detect any architectural cycle involving module X
MATCH p=(m:Module {name: $module_name})-[:DEPENDS_ON*]->(m)
RETURN [n in nodes(p) | n.name] AS cycle_path
